                'old_price'   => 45360.0,
                'images'      => ['https://sota.store/image/cache/catalog/Apple-2/iphone-16-pro-blk-01-600x600.webp'],
                'categories'  => ['used-tech'],
                'reviews'     => [
                    ['rating' => 4, 'title' => 'Відповідає опису', 'body' => 'Відмінна якість збірки, все функціонує справно. Задоволений на 100%.'],
                    ['rating' => 5, 'title' => 'Відповідає опису', 'body' => 'Отримав товар вчасно, якість відмінна. Все відповідає опису на сайті.'],
                    ['rating' => 5, 'title' => 'Гарне співвідношення ціна/якість', 'body' => 'Гарний товар за свої гроші. Функціонал повністю відповідає заявленому.'],
                ],
            ],
        ];

        Product::withoutSyncingToSearch(function () use ($products, $brands, $cats, $warehouse) {
            foreach ($products as $p) {
                if (Product::where('slug', $p['slug'])->exists()) {
                    continue;
                }

                $brand = $p['brand'] ? ($brands[$p['brand']] ?? null) : null;

                $product = Product::create([
                    'brand_id'    => $brand?->id,
                    'slug'        => $p['slug'],
                    'name'        => ['uk' => $p['name_uk'], 'en' => $p['name_uk']],
                    'description' => $p['desc_uk']
                        ? ['uk' => $p['desc_uk'], 'en' => $p['desc_uk']]
                        : null,
                    'status'      => 'active',
                ]);

                $catIds = [];
                foreach ($p['categories'] as $slug) {
                    if (!empty($cats[$slug])) {
                        $catIds[] = $cats[$slug]->id;
                    }
                }
                if (!empty($catIds)) {
                    $product->categories()->sync($catIds);
                }

                $variant = ProductVariant::create([
                    'product_id' => $product->id,
                    'sku'        => $p['sku'],
                    'price'      => $p['price'],
                    'old_price'  => $p['old_price'],
                ]);

                Stock::create([
                    'variant_id'   => $variant->id,
                    'warehouse_id' => $warehouse->id,
                    'quantity'     => rand(5, 50),
                    'reserved'     => 0,
                ]);

                foreach ($p['reviews'] as $r) {
                    DB::table('product_reviews')->insert([
                        'product_id' => $product->id,
                        'user_id'    => null,
                        'order_id'   => null,
                        'rating'     => $r['rating'],
                        'title'      => $r['title'],
                        'body'       => $r['body'],
                        'status'     => 'approved',
                        'created_at' => now(),
                        'updated_at' => now(),
                    ]);
                }
            }
        });
    }
}
